import { useState, useEffect } from 'react';
import { exportToCSV, exportToJSON, copyToClipboard } from '../utils/exportUtils';

const ExportBar = ({ data, filename = 'export', columns }) => {
  const [copied, setCopied] = useState(false);
  const [activeButton, setActiveButton] = useState(null);

  useEffect(() => {
    let timer;
    if (copied) {
      timer = setTimeout(() => setCopied(false), 2000);
    }
    return () => clearTimeout(timer);
  }, [copied]);

  const handleClick = (type) => {
    setActiveButton(type);
    switch (type) {
      case 'CSV':
        exportToCSV(data, filename, columns);
        break;
      case 'JSON':
        exportToJSON(data, filename);
        break;
      case 'Copy':
        copyToClipboard(data);
        setCopied(true);
        break;
      default:
        break;
    }
    setTimeout(() => setActiveButton(null), 150);
  };

  const baseButtonStyle = {
    padding: '4px 10px',
    borderRadius: 6,
    fontSize: 10,
    fontWeight: 600,
    fontFamily: "'JetBrains Mono', monospace",
    backgroundColor: '#111A24',
    border: '1px solid #1F2A37',
    color: '#90A3AF',
    cursor: 'pointer',
    userSelect: 'none',
    transition: 'color 0.15s ease, background-color 0.15s ease',
    marginRight: 8,
    outline: 'none',
  };

  const hoverStyle = {
    color: '#E5E7DB',
  };

  const activeStyle = {
    backgroundColor: '#60A5FA',
    color: '#111A24',
  };

  const [hovered, setHovered] = useState(null);

  const renderButton = (label) => {
    const isActive = activeButton === label;
    const isHovered = hovered === label;

    return (
      <button
        key={label}
        type="button"
        onClick={() => handleClick(label)}
        onMouseEnter={() => setHovered(label)}
        onMouseLeave={() => setHovered(null)}
        style={{
          ...baseButtonStyle,
          ...(isHovered && !isActive ? hoverStyle : {}),
          ...(isActive ? activeStyle : {}),
        }}
      >
        {label}
      </button>
    );
  };

  return (
    <div style={{ display: 'flex', alignItems: 'center', marginBottom: 8, fontFamily: "'JetBrains Mono', monospace" }}>
      {renderButton('CSV')}
      {renderButton('JSON')}
      {renderButton('Copy')}
      {copied && (
        <span
          style={{
            marginLeft: 8,
            fontSize: 10,
            fontWeight: 600,
            color: '#60A5FA',
            userSelect: 'none',
          }}
          aria-live="polite"
        >
          Copied!
        </span>
      )}
    </div>
  );
};

export default ExportBar;
